cat > data/retorica.json << 'EOF'
[
  {"id":1,"name":"Anáfora","category":"Figuras de repetición","teoria":"Repetición de una o varias palabras al comienzo de frases o versos.","ejemplo":"¡Aquí fue Troya! ¡Aquí mi espada! ¡Aquí mi valor!","ejercicio":"Escribe una frase que use anáfora.","suggestedAnswer":"Nunca olvidaré tu luz, nunca olvidaré tu calma."},
  {"id":2,"name":"Metáfora","category":"Tropos","teoria":"Identificación de un término real con otro imaginario basado en una semejanza.","ejemplo":"Tus ojos son dos luceros que guían mi noche.","ejercicio":"Crea una metáfora original.","suggestedAnswer":"El tiempo es un río que arrastra recuerdos."},
  {"id":3,"name":"Ironía","category":"Tropos","teoria":"Expresar lo contrario de lo que se piensa, con un tono que permite interpretar la intención.","ejemplo":"¡Qué día tan hermoso! (dicho durante un diluvio).","ejercicio":"Escribe una frase irónica.","suggestedAnswer":"¡Excelente noticia! perdí el último autobús."},
  {"id":4,"name":"Hipérbole","category":"Tropos","teoria":"Exageración desmedida para enfatizar una cualidad o sentimiento.","ejemplo":"Te lo he dicho un millón de veces.","ejercicio":"Crea una hipérbole.","suggestedAnswer":"Me comería un elefante entero."},
  {"id":5,"name":"Oxímoron","category":"Tropos","teoria":"Unión de dos palabras de significado opuesto que generan un efecto paradójico.","ejemplo":"Silencio atronador.","ejercicio":"Escribe un oxímoron.","suggestedAnswer":"Luz oscura."},
  {"id":6,"name":"Asíndeton","category":"Figuras sintácticas","teoria":"Omisión de conjunciones para dar agilidad y dinamismo.","ejemplo":"Llegué, vi, vencí.","ejercicio":"Escribe un asíndeton.","suggestedAnswer":"Corro, salto, grito."},
  {"id":7,"name":"Polisíndeton","category":"Figuras sintácticas","teoria":"Uso abundante de conjunciones para crear solemnidad o lentitud.","ejemplo":"Y corre y vuela y grita y arde.","ejercicio":"Escribe un polisíndeton.","suggestedAnswer":"Y el viento y la lluvia y el mar se unieron."},
  {"id":8,"name":"Quiasmo","category":"Figuras sintácticas","teoria":"Estructura cruzada (AB/BA) que produce paralelismo invertido.","ejemplo":"Cuando quiero llorar no lloro, y a veces lloro sin querer.","ejercicio":"Crea un quiasmo.","suggestedAnswer":"El trabajo para vivir, no vivo para trabajar."},
  {"id":9,"name":"Aliteración","category":"Figuras de sonido","teoria":"Repetición de sonidos consonánticos para crear ritmo o musicalidad.","ejemplo":"El ruido con que rueda la ronca tempestad.","ejercicio":"Crea una aliteración.","suggestedAnswer":"Ruedan rugiendo ríos rojos."},
  {"id":10,"name":"Metonimia","category":"Tropos","teoria":"Designar una cosa con el nombre de otra con la que mantiene una relación.","ejemplo":"Leer a Cervantes (por sus obras).","ejercicio":"Escribe una metonimia.","suggestedAnswer":"Tomar una copa (por el vino que contiene)."},
  {"id":11,"name":"Sinécdoque","category":"Tropos","teoria":"Designar el todo por la parte o viceversa.","ejemplo":"Diez velas en el mar (por diez barcos).","ejercicio":"Crea una sinécdoque.","suggestedAnswer":"Necesitamos manos para terminar el proyecto."},
  {"id":12,"name":"Antítesis","category":"Figuras de pensamiento","teoria":"Contraposición de dos ideas o términos de significado contrario.","ejemplo":"Ir y quedarse, y con quedar partirse.","ejercicio":"Crea una antítesis.","suggestedAnswer":"Pequeño en estatura, gigante en coraje."},
  {"id":13,"name":"Paradoja","category":"Figuras de pensamiento","teoria":"Afirmación aparentemente contradictoria que encierra una verdad profunda.","ejemplo":"Vivo sin vivir en mí.","ejercicio":"Escribe una paradoja.","suggestedAnswer":"Para llegar a la luz hay que atravesar la propia sombra."},
  {"id":14,"name":"Gradación","category":"Figuras de pensamiento","teoria":"Serie de términos ordenados de menor a mayor intensidad.","ejemplo":"Al principio fue una chispa, luego llama, después incendio.","ejercicio":"Escribe una gradación.","suggestedAnswer":"Molestia, ira, furia, explosión."},
  {"id":15,"name":"Interrogación retórica","category":"Figuras dialógicas","teoria":"Pregunta que no espera respuesta, sino que afirma o niega con fuerza.","ejemplo":"¿Acaso no es obvio que debemos actuar?","ejercicio":"Escribe una interrogación retórica.","suggestedAnswer":"¿Quién no quiere un futuro mejor?"},
  {"id":16,"name":"Exclamación","category":"Figuras dialógicas","teoria":"Expresión vehemente de una emoción mediante una oración exclamativa.","ejemplo":"¡Oh, tiempos! ¡Oh, costumbres!","ejercicio":"Crea una exclamación.","suggestedAnswer":"¡Qué maravilla de horizontes!"},
  {"id":17,"name":"Apóstrofe","category":"Figuras dialógicas","teoria":"Dirigirse a un interlocutor ausente o a un ser inanimado.","ejemplo":"¡Oh muerte, ven callada!","ejercicio":"Escribe un apóstrofe.","suggestedAnswer":"Silencio, amigo mío, acompáñame esta noche."},
  {"id":18,"name":"Prosopopeya","category":"Figuras de pensamiento","teoria":"Atribuir cualidades humanas a objetos o ideas abstractas.","ejemplo":"La noche vestía su manto de estrellas.","ejercicio":"Personifica la soledad.","suggestedAnswer":"La soledad me susurra al oído canciones viejas."},
  {"id":19,"name":"Símil","category":"Tropos","teoria":"Comparación explícita usando 'como', 'cual' o 'parece'.","ejemplo":"Blanca como la nieve.","ejercicio":"Escribe un símil.","suggestedAnswer":"Triste como un tren que se aleja sin pasajeros."},
  {"id":20,"name":"Hipérbaton","category":"Figuras sintácticas","teoria":"Alteración del orden lógico de las palabras.","ejemplo":"Del salón en el ángulo oscuro.","ejercicio":"Reordena una frase con hipérbaton.","suggestedAnswer":"En su cuna duerme plácidamente el niño."},
  {"id":21,"name":"Elipsis","category":"Figuras sintácticas","teoria":"Supresión de un elemento lingüístico que se sobrentiende.","ejemplo":"Él llegó tarde; ella, puntual.","ejercicio":"Escribe una elipsis.","suggestedAnswer":"Unos lloraban la derrota; otros, la victoria."},
  {"id":22,"name":"Anacoluto","category":"Figuras sintácticas","teoria":"Ruptura de la concordancia sintáctica.","ejemplo":"A mí, que me castiguen si no cumplo.","ejercicio":"Escribe un anacoluto.","suggestedAnswer":"A los jóvenes, hay que darles oportunidades."},
  {"id":23,"name":"Paralelismo","category":"Figuras sintácticas","teoria":"Repetición de una misma estructura gramatical.","ejemplo":"Tu risa es primavera, tu mirada es fuente.","ejercicio":"Crea un paralelismo.","suggestedAnswer":"Bello como el alba, bello como el jazmín."},
  {"id":24,"name":"Epanadiplosis","category":"Figuras de repetición","teoria":"Comenzar y terminar una frase con la misma palabra.","ejemplo":"Verde que te quiero verde.","ejercicio":"Escribe una epanadiplosis.","suggestedAnswer":"Frío el amanecer, amanecer frío."},
  {"id":25,"name":"Epífora","category":"Figuras de repetición","teoria":"Repetición de una palabra al final de frases consecutivas.","ejemplo":"Tu juventud es pasajera, tu belleza es pasajera.","ejercicio":"Crea una epífora.","suggestedAnswer":"Llevo tu risa en el alma, llevo tu llanto en el alma."},
  {"id":26,"name":"Reduplicación","category":"Figuras de sonido","teoria":"Repetición inmediata de una palabra o sílaba.","ejemplo":"Ríe, ríe, que la vida es breve.","ejercicio":"Crea una reduplicación.","suggestedAnswer":"Bajo, bajo, que el ruido no nos oiga."},
  {"id":27,"name":"Derivación","category":"Figuras de sonido","teoria":"Repetición de palabras de la misma familia léxica.","ejemplo":"Temprano madrugó la madrugadora.","ejercicio":"Escribe una derivación.","suggestedAnswer":"La luz alumbra al lucero luminoso."},
  {"id":28,"name":"Calambur","category":"Figuras de sonido","teoria":"Juego de palabras que reagrupa sílabas para crear doble sentido.","ejemplo":"Entre el clavel blanco y la rosa roja, su majestad escoja.","ejercicio":"Inventa un calambur.","suggestedAnswer":"A este paso, ¿paso o no paso?"},
  {"id":29,"name":"Paronomasia","category":"Figuras de sonido","teoria":"Empleo de palabras de sonido parecido pero significado diferente.","ejemplo":"Por los altos tejados, tantos tejados de teja.","ejercicio":"Escribe una paronomasia.","suggestedAnswer":"Mi casa es mi caza diaria."},
  {"id":30,"name":"Onomatopeya","category":"Figuras de sonido","teoria":"Palabra que imita el sonido de aquello que designa.","ejemplo":"El tic-tac del reloj.","ejercicio":"Crea una onomatopeya.","suggestedAnswer":"El zum zum de la abeja."},
  {"id":31,"name":"Zeugma","category":"Figuras sintácticas","teoria":"Elipsis de un verbo que se aplica a varios miembros.","ejemplo":"Unos lloraban, otros reían.","ejercicio":"Escribe un zeugma.","suggestedAnswer":"Él estudia medicina; ella, derecho."},
  {"id":32,"name":"Silepsis","category":"Figuras sintácticas","teoria":"Concordancia por el sentido más que por la norma.","ejemplo":"La mayoría están de acuerdo.","ejercicio":"Crea una silepsis.","suggestedAnswer":"El grupo de personas se fueron contentas."},
  {"id":33,"name":"Hendíadis","category":"Figuras sintácticas","teoria":"Expresión de una idea mediante dos términos unidos por 'y'.","ejemplo":"Noche y lobreguez (por noche lobregueciente).","ejercicio":"Transforma 'larga espera' en hendíadis.","suggestedAnswer":"Espera y largura."},
  {"id":34,"name":"Retruécano","category":"Figuras de pensamiento","teoria":"Repetición de una frase invirtiendo el orden de sus elementos.","ejemplo":"No estudias para vivir, sino que vives para estudiar.","ejercicio":"Crea un retruécano.","suggestedAnswer":"No comemos para vivir, vivimos para comer."},
  {"id":35,"name":"Concatenación","category":"Figuras de pensamiento","teoria":"La última palabra de un segmento es la primera del siguiente.","ejemplo":"Todo pasa, todo llega, llega la calma, la calma olvida.","ejercicio":"Escribe una concatenación.","suggestedAnswer":"Corre el río, río que canta, canta la noche."},
  {"id":36,"name":"Epanalepsis","category":"Figuras de repetición","teoria":"Repetir al final de una frase la misma palabra del principio.","ejemplo":"Verde que te quiero verde.","ejercicio":"Escribe una epanalepsis.","suggestedAnswer":"Silencioso como el humo, el humo silencioso."},
  {"id":37,"name":"Pleonasmo","category":"Figuras sintácticas","teoria":"Empleo de palabras redundantes que refuerzan el significado.","ejemplo":"Lo vi con mis propios ojos.","ejercicio":"Escribe un pleonasmo.","suggestedAnswer":"Sube arriba y baja abajo."},
  {"id":38,"name":"Enálage","category":"Figuras sintácticas","teoria":"Cambio de una categoría gramatical por otra.","ejemplo":"El ayer presente.","ejercicio":"Usa un sustantivo como adjetivo.","suggestedAnswer":"Una mirada metal."},
  {"id":39,"name":"Antonomasia","category":"Tropos","teoria":"Sustitución de un nombre propio por un epíteto.","ejemplo":"El ruiseñor de Sevilla (por Bécquer).","ejercicio":"Usa una antonomasia.","suggestedAnswer":"Ven aquí, Hércules, levanta esta mesa."},
  {"id":40,"name":"Lítote","category":"Figuras de pensamiento","teoria":"Atenuación por negación de lo contrario.","ejemplo":"No está mal (por 'está bien').","ejercicio":"Usa lítote.","suggestedAnswer":"No es nada despreciable."},
  {"id":41,"name":"Perífrasis","category":"Tropos","teoria":"Rodeo de palabras para evitar el término directo.","ejemplo":"El autor de El Quijote (en lugar de Cervantes).","ejercicio":"Sustituye 'muerte' con una perífrasis.","suggestedAnswer":"El viaje sin retorno."},
  {"id":42,"name":"Símbolo","category":"Tropos","teoria":"Objeto que representa una idea abstracta por convención.","ejemplo":"La paloma blanca como símbolo de paz.","ejercicio":"Menciona un símbolo de libertad.","suggestedAnswer":"El pájaro volando libre."},
  {"id":43,"name":"Alegoría","category":"Tropos","teoria":"Metáfora continuada donde conceptos abstractos se representan mediante imágenes.","ejemplo":"El mito de la caverna de Platón.","ejercicio":"Crea una alegoría breve del paso del tiempo.","suggestedAnswer":"Un río que arrastra hojas y nunca se detiene."},
  {"id":44,"name":"Sinestesia","category":"Tropos","teoria":"Atribución de una sensación a un sentido que no le corresponde.","ejemplo":"Color áspero, sonido dulce.","ejercicio":"Escribe una sinestesia.","suggestedAnswer":"El azul de la música."},
  {"id":45,"name":"Eufemismo","category":"Tropos","teoria":"Sustitución de una expresión malsonante por una más suave.","ejemplo":"Pasar a mejor vida (por morir).","ejercicio":"Escribe un eufemismo para 'despedir a un empleado'.","suggestedAnswer":"Reestructurar el personal."},
  {"id":46,"name":"Disonancia","category":"Figuras de sonido","teoria":"Combinación de sonidos ásperos o desagradables (cacofonía buscada).","ejemplo":"El crótalo craso crascita.","ejercicio":"Crea una disonancia.","suggestedAnswer":"Trepando por tapias, topé con un títere tieso."},
  {"id":47,"name":"Hipocorístico","category":"Figuras afectivas","teoria":"Uso de diminutivos o formas cariñosas.","ejemplo":"Ven aquí, hijito.","ejercicio":"Añade un hipocorístico a un sustantivo abstracto.","suggestedAnswer":"El problemita se resolvió solito."},
  {"id":48,"name":"Écfrasis","category":"Figuras de pensamiento","teoria":"Descripción literaria de una obra de arte visual.","ejemplo":"Describir un cuadro de Velázquez con palabras.","ejercicio":"Describe una fotografía ficticia.","suggestedAnswer":"La foto mostraba un niño descalzo sobre el barro, el cielo gris."},
  {"id":49,"name":"Metalepsis","category":"Figuras narrativas","teoria":"Transgresión de los niveles narrativos (el narrador salta a la historia).","ejemplo":"El héroe levantó la espada y yo, el autor, sentí miedo.","ejercicio":"Escribe una metalepsis.","suggestedAnswer":"El personaje cerró el libro y me dijo: '¿tú crees que existo?'."},
  {"id":50,"name":"Tautología","category":"Figuras de pensamiento","teoria":"Repetición innecesaria de una misma idea con distintas palabras.","ejemplo":"Subir arriba.","ejercicio":"Crea una tautología.","suggestedAnswer":"Volver a repetir otra vez."},
  {"id":51,"name":"Entimema","category":"Argumentación","teoria":"Silogismo retórico incompleto donde se omite una premisa por obvia.","ejemplo":"Es mortal, porque es hombre (se omite 'todos los hombres son mortales').","ejercicio":"Formula un entimema.","suggestedAnswer":"Estudia mucho, porque quiere triunfar."},
  {"id":52,"name":"Sorites","category":"Argumentación","teoria":"Cadena de razonamientos encadenados donde el predicado de uno es sujeto del siguiente.","ejemplo":"Quien estudia, aprende; quien aprende, mejora; quien mejora, triunfa.","ejercicio":"Construye un sorites.","suggestedAnswer":"Quien tiene paciencia, sabe esperar; quien sabe esperar, halla oportunidad."},
  {"id":53,"name":"Dilema","category":"Argumentación","teoria":"Planteamiento de dos opciones igualmente desfavorables.","ejemplo":"Si aceptas, pierdes tu libertad; si rechazas, pierdes tu oportunidad.","ejercicio":"Crea un dilema.","suggestedAnswer":"Si tomas el empleo estable, no tienes tiempo; si tomas el flexible, no tienes dinero."},
  {"id":54,"name":"A fortiori","category":"Argumentación","teoria":"Razonamiento que va de lo más evidente a lo menos evidente.","ejemplo":"Si cuidas una planta, con mayor razón cuidarás a un hijo.","ejercicio":"Escribe un argumento a fortiori.","suggestedAnswer":"Si estudiar una hora mejora tus notas, con mayor razón estudiando dos horas serás excelente."},
  {"id":55,"name":"Exordio","category":"Dispositio","teoria":"Parte inicial del discurso para captar atención y benevolencia.","ejemplo":"Comenzar con una cita impactante.","ejercicio":"Redacta un exordio breve.","suggestedAnswer":"¿Sabías que cada minuto se vierte un camión de basura al mar?"},
  {"id":56,"name":"Narratio","category":"Dispositio","teoria":"Exposición clara y concisa de los hechos relevantes.","ejemplo":"En un juicio, se narra cronológicamente lo sucedido.","ejercicio":"Escribe una narratio.","suggestedAnswer":"El coche circulaba por la avenida cuando un peatón cruzó indebidamente."},
  {"id":57,"name":"Confirmatio","category":"Dispositio","teoria":"Presentación de pruebas y razones que apoyan la tesis.","ejemplo":"Citar estadísticas, testimonios, ejemplos.","ejercicio":"Propón una confirmatio simple.","suggestedAnswer":"El teletrabajo reduce el estrés del tráfico, mejora la concentración y disminuye la huella de carbono."},
  {"id":58,"name":"Refutatio","category":"Dispositio","teoria":"Anticipación y respuesta a los posibles argumentos contrarios.","ejemplo":"Alguien podría decir que el teletrabajo aísla, pero las videollamadas fomentan la comunicación.","ejercicio":"Refuta un argumento.","suggestedAnswer":"Es falso que los jóvenes no lean; muchos leen en formato digital y participan en clubes literarios."},
  {"id":59,"name":"Peroratio","category":"Dispositio","teoria":"Conclusión que resume y mueve a la acción o emoción.","ejemplo":"Por todo ello, os pido que votéis sí a la propuesta.","ejercicio":"Redacta un epílogo breve.","suggestedAnswer":"Me llevo su amistad y les dejo mi gratitud. No digo adiós, digo hasta siempre."},
  {"id":60,"name":"Refrán","category":"Tradición castellana","teoria":"Enunciado breve que condensa enseñanza popular, funcionando como entimema.","ejemplo":"A quien madruga, Dios le ayuda.","ejercicio":"Explica el entimema detrás de un refrán.","suggestedAnswer":"Premisa omitida: el mañana puede traer imprevistos; por tanto, actuar hoy es más seguro."},
  {"id":61,"name":"Conceptismo","category":"Tradición castellana","teoria":"Estilo basado en asociación ingeniosa de conceptos y juegos de palabras.","ejemplo":"Poderoso caballero es don Dinero.","ejercicio":"Crea un conceptismo breve.","suggestedAnswer":"El tiempo es un reloj que siempre da la hora de la verdad."},
  {"id":62,"name":"Culteranismo","category":"Tradición castellana","teoria":"Estilo que embellece el lenguaje mediante latinismos y metáforas puras.","ejemplo":"Infame turba de nocturnas aves (por murciélagos).","ejercicio":"Reescribe 'el atardecer en el campo' con culteranismo.","suggestedAnswer":"En occidente el sol, purpúreo jazmín, exhalaba su ocaso entre espigas de oro."},
  {"id":63,"name":"Ubi sunt","category":"Tópicos literarios","teoria":"Pregunta retórica por el paradero de personas o glorias pasadas.","ejemplo":"¿Qué se hicieron las damas, sus tocados, sus olores?","ejercicio":"Escribe un ubi sunt.","suggestedAnswer":"¿Dónde están aquellos juegos de la tarde, las risas y los secretos compartidos?"},
  {"id":64,"name":"Locus amoenus","category":"Tópicos literarios","teoria":"Descripción idealizada de un paisaje placentero.","ejemplo":"Prado de verdor sin par, fuente de clara agua.","ejercicio":"Describe un locus amoenus breve.","suggestedAnswer":"Un arroyo cantarín, césped suave y un sauce que abraza la orilla."},
  {"id":65,"name":"Contemptus mundi","category":"Tópicos literarios","teoria":"Desprecio del mundo y sus vanidades, invitación a lo espiritual.","ejemplo":"Vanidad de vanidades, todo es vanidad.","ejercicio":"Escribe una frase con contemptus mundi.","suggestedAnswer":"El oro brilla pero no calienta el alma."},
  {"id":66,"name":"Agudeza","category":"Tradición castellana","teoria":"Capacidad de establecer relaciones ingeniosas entre conceptos.","ejemplo":"Lo bueno, si breve, dos veces bueno.","ejercicio":"Crea una agudeza.","suggestedAnswer":"La paciencia es el arte de esperar sin desesperar."},
  {"id":67,"name":"Imagen surrealista","category":"Vanguardias","teoria":"Asociación libre de realidades distantes, onírica.","ejemplo":"El teléfono con langosta de Dalí.","ejercicio":"Escribe una imagen surrealista.","suggestedAnswer":"El reloj derretido goteaba minutos de miel sobre una sombrilla."},
  {"id":68,"name":"Monólogo interior","category":"Vanguardias","teoria":"Flujo de pensamientos sin estructura lógica.","ejemplo":"Frío... la ventana... las once... ese ruido otra vez...","ejercicio":"Redacta un monólogo interior breve.","suggestedAnswer":"Miro la puerta... minuto diez... ese cuadro torcido... y si no viene... no, vendrá."},
  {"id":69,"name":"Intertextualidad","category":"Teoría literaria","teoria":"Relación de un texto con otros textos (citas, alusiones).","ejemplo":"Comenzar una novela con 'En un lugar de la Mancha...' sabiendo que es Cervantes.","ejercicio":"Escribe una intertextualidad.","suggestedAnswer":"Ser o no ser, esa es la cuestión, aunque aquí el dilema sea otro."},
  {"id":70,"name":"Metaficción","category":"Teoría literaria","teoria":"Obra que se autorrefiere y expone sus propios mecanismos.","ejemplo":"Un narrador que dice 'en este capítulo inventaré un final'.","ejercicio":"Escribe una oración metaficticia.","suggestedAnswer":"El escritor dudó: si ponía aquí un beso, tal vez el lector sonreiría."},
  {"id":71,"name":"Esperpento","category":"Vanguardias","teoria":"Deformación grotesca y sistemática de la realidad.","ejemplo":"Los héroes clásicos se convierten en muñecos patéticos.","ejercicio":"Describe algo con rasgos esperpénticos.","suggestedAnswer":"El coche fúnebre parecía una berenjena gigante, y las coronas de flores bailaban al son de una chicharra."},
  {"id":72,"name":"Silencio retórico","category":"Figuras finales","teoria":"Omisión deliberada del discurso que comunica por ausencia.","ejemplo":"En un debate, callar después de una acusación puede ser más elocuente.","ejercicio":"Propón una situación donde el silencio sea una respuesta retórica poderosa.","suggestedAnswer":"Ante una mentira evidente, el silencio sostenido y la mirada fija pueden desmontarla sin palabras."},
  {"id":73,"name":"Analogía","category":"Operaciones mentales","teoria":"Establecer similitudes entre dominios diferentes.","ejemplo":"El cerebro es como un ordenador.","ejercicio":"Crea una analogía.","suggestedAnswer":"La educación es como la jardinería: requiere paciencia, abono y riego constante."},
  {"id":74,"name":"Inversión","category":"Operaciones mentales","teoria":"Dar la vuelta a un orden esperado para producir extrañeza.","ejemplo":"De pronto, del cielo, cayó una estrella.","ejercicio":"Invierte el orden lógico de una frase.","suggestedAnswer":"Al gato persigue el perro."},
  {"id":75,"name":"Omisión","category":"Operaciones mentales","teoria":"Suprimir información que el receptor puede completar.","ejemplo":"A grandes males, grandes remedios.","ejercicio":"Construye una omisión del verbo.","suggestedAnswer":"Ella, el premio; él, la gloria."},
  {"id":76,"name":"Exageración","category":"Operaciones mentales","teoria":"Aumentar desmesuradamente las cualidades de algo.","ejemplo":"Me muero de hambre.","ejercicio":"Exagera la belleza de una puesta de sol.","suggestedAnswer":"El sol se incendió y pintó el cielo con mil lenguas de fuego."},
  {"id":77,"name":"Prosografía","category":"Figuras descriptivas","teoria":"Descripción física de una persona o personaje.","ejemplo":"Era de mediana estatura, barba entrecanosa.","ejercicio":"Describe prosográficamente a un sabio.","suggestedAnswer":"Frente amplia, gafas de concha, dedos manchados de tinta."},
  {"id":78,"name":"Etopeia","category":"Figuras descriptivas","teoria":"Descripción de cualidades morales o psicológicas.","ejemplo":"Valiente y generoso, siempre dispuesto a ayudar.","ejercicio":"Escribe una etopeia.","suggestedAnswer":"De sonrisa fácil, nunca pierde la esperanza y contagia su fe."},
  {"id":79,"name":"Sermocinatio","category":"Figuras dialógicas","teoria":"Atribuir palabras a un personaje ausente.","ejemplo":"Imagina que digo: 'yo nunca fallaría'.","ejercicio":"Introduce un sermocinatio.","suggestedAnswer":"Y entonces el crítico dirá: 'todo esto no sirve de nada'."},
  {"id":80,"name":"Chiasmus conceptual","category":"Figuras de pensamiento","teoria":"Cruce de conceptos abstractos en lugar de palabras.","ejemplo":"El amor sin fe no es amor, la fe sin amor no es fe.","ejercicio":"Crea un quiasmo conceptual.","suggestedAnswer":"No basta saber para poder, hay que poder para saber."},
  {"id":81,"name":"Analepsis","category":"Figuras narrativas","teoria":"Salto atrás en el tiempo del relato.","ejemplo":"Recordó aquella tarde de lluvia cuando todo comenzó.","ejercicio":"Escribe una analepsis.","suggestedAnswer":"Mientras caminaba, volvió a pensar en la noche que conoció a Lucía."},
  {"id":82,"name":"Prolepsis","category":"Figuras narrativas","teoria":"Anuncio de un suceso futuro antes de que ocurra.","ejemplo":"Lo que sucedería después cambiaría su vida para siempre.","ejercicio":"Usa una prolepsis.","suggestedAnswer":"Aún no lo sabía, pero aquella carta sería su perdición."},
  {"id":83,"name":"Anástrofe","category":"Figuras sintácticas","teoria":"Inversión del orden habitual de dos palabras.","ejemplo":"De corazón sincero (en vez de 'sincero corazón').","ejercicio":"Escribe una anástrofe.","suggestedAnswer":"De tierra madre."},
  {"id":84,"name":"Hirmos","category":"Figuras de argumentación","teoria":"Flujo continuo de frases de igual estructura.","ejemplo":"Llegó, miró, venció y partió triunfante.","ejercicio":"Crea un hirmos.","suggestedAnswer":"Corrió, saltó, cayó, rió."},
  {"id":85,"name":"Exclamación irónica","category":"Figuras dialógicas","teoria":"Exclamación que expresa ironía.","ejemplo":"¡Qué inteligente! (ante un error tonto).","ejercicio":"Exclama irónicamente.","suggestedAnswer":"¡Qué puntualidad, no faltaba más!"},
  {"id":86,"name":"Apódosis enfática","category":"Figuras sintácticas","teoria":"Anteponer la conclusión a la condición.","ejemplo":"Cantaré, si tú me escuchas.","ejercicio":"Transforma una condicional.","suggestedAnswer":"Aprobarás, si estudias."},
  {"id":87,"name":"Suspensión","category":"Figuras sintácticas","teoria":"Construcción larga donde el sentido se completa al final.","ejemplo":"Aunque llueva, truene o nieve, yo iré.","ejercicio":"Escribe una suspensión.","suggestedAnswer":"Después de tanto correr, saltar y esquivar obstáculos, llegó por fin."},
  {"id":88,"name":"Bdelygmia","category":"Figuras de pensamiento","teoria":"Serie de invectivas o insultos.","ejemplo":"Traidor, mentiroso, cobarde, indigno.","ejercicio":"Escribe una bdelygmia breve.","suggestedAnswer":"Perezoso, indolente, parásito, eterno insatisfecho."},
  {"id":89,"name":"Inventio","category":"Operaciones del orador","teoria":"Búsqueda y selección de argumentos.","ejemplo":"Para defender la paz, el orador reúne estadísticas.","ejercicio":"Elige un tema y enumera argumentos.","suggestedAnswer":"Prohibición de plásticos: impacto ambiental, alternativas biodegradables, coste-beneficio."},
  {"id":90,"name":"Dispositio","category":"Operaciones del orador","teoria":"Organización de las partes del discurso.","ejemplo":"Exordio, narración, argumentación, refutación, epílogo.","ejercicio":"Describe la dispositio de un discurso.","suggestedAnswer":"Exordio emotivo, narración de necesidad, argumentos médicos, refutación de mitos, epílogo solidario."},
  {"id":91,"name":"Elocutio","category":"Operaciones del orador","teoria":"Vestir las ideas con palabras adecuadas.","ejemplo":"No es lo mismo 'el perro murió' que 'el fiel compañero exhaló su último aliento'.","ejercicio":"Transforma 'hace mucho frío' con elocutio.","suggestedAnswer":"El hielo muerde los huesos y el viento afila cuchillos invisibles."},
  {"id":92,"name":"Memoria","category":"Operaciones del orador","teoria":"Técnicas para recordar el discurso.","ejemplo":"Asociar cada punto del discurso con una habitación de la casa.","ejercicio":"Propón un método mnemotécnico.","suggestedAnswer":"Usar la primera sílaba de cada punto para formar una palabra inventada: PAISA."},
  {"id":93,"name":"Actio","category":"Operaciones del orador","teoria":"Uso de la voz, el gesto y el cuerpo.","ejemplo":"Cicerón decía que la acción es elocuencia del cuerpo.","ejercicio":"Señala un gesto que refuerce 'unidad'.","suggestedAnswer":"Juntar las palmas de las manos y elevarlas ligeramente."},
  {"id":94,"name":"Enthymeme","category":"Argumentación","teoria":"Variante del entimema con premisa oculta.","ejemplo":"Es inteligente, porque es filósofo (se omite 'todo filósofo es inteligente').","ejercicio":"Crea un enthymeme.","suggestedAnswer":"Es valiente, porque es bombero."},
  {"id":95,"name":"Epitrope","category":"Figuras de pensamiento","teoria":"Concesión irónica o resignada.","ejemplo":"Bien, hazlo a tu manera, ya verás qué pasa.","ejercicio":"Escribe una epitrope.","suggestedAnswer":"Claro, no estudies; luego no te quejes de las notas."},
  {"id":96,"name":"Aposiopesis","category":"Figuras de pensamiento","teoria":"Interrupción brusca del discurso para sugerir algo no dicho.","ejemplo":"Si vuelves a hacer eso... (se entiende la amenaza).","ejercicio":"Usa aposiopesis.","suggestedAnswer":"Si llegas tarde otra vez..."},
  {"id":97,"name":"Correctio","category":"Figuras de pensamiento","teoria":"Corrección o matización de lo dicho anteriormente.","ejemplo":"Llegó tarde, o mejor dicho, llegó cuando ya todos se habían ido.","ejercicio":"Escribe una correctio.","suggestedAnswer":"Es alto, más bien es un gigante."},
  {"id":98,"name":"Distributio","category":"Figuras de pensamiento","teoria":"División de un todo en sus partes.","ejemplo":"Los romanos conquistaron Hispania, la Galia y Grecia.","ejercicio":"Escribe una distributio.","suggestedAnswer":"El curso abarca ortografía, sintaxis y redacción."},
  {"id":99,"name":"Expeditio","category":"Figuras de pensamiento","teoria":"Eliminación de opciones hasta quedarse con una.","ejemplo":"No es por falta de tiempo, ni por falta de ganas, es por falta de recursos.","ejercicio":"Escribe una expeditio.","suggestedAnswer":"No falló por ignorancia, ni por descuido, sino por terquedad."},
  {"id":100,"name":"Operación retórica fundamental: analogía","category":"Cierre teórico","teoria":"Trasladar estructuras de un campo a otro para crear comprensión.","ejemplo":"Así como la espada es al guerrero, la pluma es al escritor.","ejercicio":"Crea una analogía entre retórica y arquitectura.","suggestedAnswer":"La retórica es a las ideas lo que la arquitectura es a los espacios: orden, belleza y función."}
]
